

<template><section class="page"><RouterLink to="/datasets">← {{t('promptops.datasets.back')}}</RouterLink><p v-if="loading">{{t('promptops.common.loading')}}</p><div v-else-if="error" class="error">{{error}}</div><div v-else-if="!dataset" class="empty"><h2>{{t('promptops.datasets.notFound')}}</h2><RouterLink to="/datasets">{{t('promptops.datasets.back')}}</RouterLink></div><template v-else><header><div><h2>{{dataset.name}}</h2><p>{{dataset.description}}</p><span class="status">{{t(`promptops.datasets.${dataset.status}`)}}</span></div><div class="actions"><button @click="exportDataset">{{t('promptops.datasets.exportDataset')}}</button><button @click="duplicateDataset">{{t('promptops.datasets.duplicate')}}</button><button v-if="dataset.status==='active'" @click="editingDataset=true">{{t('promptops.datasets.metadata')}}</button><button v-if="dataset.status==='active'" @click="archiveDataset">{{t('promptops.datasets.archive')}}</button><button v-else @click="restoreDataset">{{t('promptops.datasets.restore')}}</button><button :disabled="readonly||!cases.length" @click="evaluationOpen=true">{{t('promptops.datasets.runEvaluation')}}</button></div></header><div class="meta"><span>{{t('promptops.datasets.testCases')}}: {{cases.length}}</span><span>{{t('promptops.datasets.created')}}: {{date(dataset.createdAt)}}</span><span>{{t('promptops.datasets.updated')}}: {{date(dataset.updatedAt)}}</span></div><p v-if="readonly" class="notice">{{t('promptops.datasets.archivedReadonly')}}</p><div class="toolbar"><input v-model="search" :placeholder="t('promptops.datasets.caseSearch')"><input v-model="tag" :placeholder="t('promptops.datasets.tags')"><select v-model="sort"><option value="updatedAt">{{t('promptops.datasets.updated')}}</option><option value="createdAt">{{t('promptops.datasets.created')}}</option><option value="name">{{t('promptops.datasets.name')}}</option></select><button :disabled="readonly" @click="editorOpen=true">{{t('promptops.datasets.addCase')}}</button><button class="danger" :disabled="readonly||!selected.length" @click="batchDelete">{{t('promptops.datasets.batchDelete')}} ({{selected.length}})</button></div><TestCaseTable :items="paged" :selected="selected" :readonly="readonly" @toggle="toggle" @toggle-all="toggleAll" @edit="editCase" @duplicate="duplicateCase" @delete="deleteCase"/><div class="pager"><button :disabled="page<=1" @click="page--">‹</button><span>{{page}}</span><button :disabled="page*pageSize>=filtered.length" @click="page++">›</button></div><DatasetEditor v-if="editingDataset" :dataset="dataset" @close="editingDataset=false" @save="saveDataset"/><TestCaseEditor v-if="editorOpen" :dataset-id="dataset.id" :workspace-id="dataset.workspaceId" :value="editingCase" @close="closeCase" @save="saveCase"/><EvaluationConfigDialog v-if="evaluationOpen" :dataset="dataset" :test-cases="cases" :selected-ids="selected" @close="evaluationOpen=false" @started="evaluationStarted"/></template></section></template>
<script setup lang="ts">import{computed,ref,watch}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import{useI18n}from'vue-i18n';import type{Dataset,DatasetTestCase}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import DatasetEditor from'../../components/promptops/datasets/DatasetEditor.vue';import TestCaseEditor from'../../components/promptops/datasets/TestCaseEditor.vue';import TestCaseTable from'../../components/promptops/datasets/TestCaseTable.vue';import EvaluationConfigDialog from'../../components/promptops/evaluations/EvaluationConfigDialog.vue';const{t}=useI18n(),route=useRoute(),router=useRouter(),services=usePromptOpsServices();const dataset=ref<Dataset>(),cases=ref<DatasetTestCase[]>([]),loading=ref(false),error=ref(''),search=ref(''),tag=ref(''),sort=ref<'name'|'createdAt'|'updatedAt'>('updatedAt'),page=ref(1),selected=ref<string[]>([]),editingDataset=ref(false),editorOpen=ref(false),editingCase=ref<DatasetTestCase>(),evaluationOpen=ref(false),pageSize=10;const readonly=computed(()=>dataset.value?.status==='archived');const filtered=computed(()=>cases.value.filter(item=>{const q=search.value.toLowerCase();return(!q||`${item.name} ${JSON.stringify(item.variables)} ${String(item.expectedOutput??'')}`.toLowerCase().includes(q))&&(!tag.value||item.tags?.includes(tag.value))}).sort((a,b)=>sort.value==='name'?a.name.localeCompare(b.name):String(b[sort.value]).localeCompare(String(a[sort.value]))));const paged=computed(()=>filtered.value.slice((page.value-1)*pageSize,page.value*pageSize));watch([search,tag,sort],()=>page.value=1);const load=async()=>{loading.value=true;error.value='';try{const detail=await services.datasetQueryService.getDetail(String(route.params.datasetId));dataset.value=detail?.dataset;cases.value=detail?.testCases??[];selected.value=[];if(page.value>Math.max(1,Math.ceil(cases.value.length/pageSize)))page.value=Math.max(1,Math.ceil(cases.value.length/pageSize))}catch(cause){error.value=cause instanceof Error?cause.message:String(cause)}finally{loading.value=false}};watch(()=>route.params.datasetId,load,{immediate:true});const saveDataset=async(value:{name:string;description:string})=>{if(!dataset.value)return;await services.datasetService.update(dataset.value.id,value);editingDataset.value=false;await load()};const archiveDataset=async()=>{if(dataset.value&&confirm(String(t('promptops.datasets.archiveConfirm')))){await services.datasetService.archive(dataset.value.id);await load()}};const restoreDataset=async()=>{if(dataset.value){await services.datasetService.restore(dataset.value.id);await load()}};const duplicateDataset=async()=>{if(dataset.value){const copy=await services.datasetService.duplicate(dataset.value.id);await router.push(`/datasets/${copy.id}`)}};const closeCase=()=>{editorOpen.value=false;editingCase.value=undefined};const editCase=(item:DatasetTestCase)=>{editingCase.value=item;editorOpen.value=true};const saveCase=async(value:Omit<DatasetTestCase,'id'|'workspaceId'|'datasetId'|'createdAt'|'updatedAt'>|DatasetTestCase)=>{if(!dataset.value)return;if('id'in value)await services.datasetService.updateTestCase(value);else await services.datasetService.addTestCase(dataset.value.id,value);closeCase();await load()};const duplicateCase=async(item:DatasetTestCase)=>{await services.datasetService.duplicateTestCase(item.id);await load()};const deleteCase=async(item:DatasetTestCase)=>{if(confirm(String(t('promptops.datasets.deleteConfirm')))){await services.datasetService.deleteTestCase(item.id);await load()}};const toggle=(id:string)=>selected.value=selected.value.includes(id)?selected.value.filter(x=>x!==id):[...selected.value,id];const toggleAll=(checked:boolean)=>selected.value=checked?[...new Set([...selected.value,...paged.value.map(x=>x.id)])]:selected.value.filter(id=>!paged.value.some(x=>x.id===id));const batchDelete=async()=>{if(!dataset.value||!confirm(String(t('promptops.datasets.batchDeleteConfirm'))))return;await services.datasetService.deleteTestCases(dataset.value.id,selected.value);selected.value=[];await load()};const exportDataset=async()=>{if(!dataset.value)return;const value=await services.datasetService.exportDocument(dataset.value.id),blob=new Blob([JSON.stringify(value,null,2)],{type:'application/json;charset=utf-8'}),url=URL.createObjectURL(blob),a=document.createElement('a');a.href=url;a.download=`dataset-${dataset.value.id}-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(url)};const evaluationStarted=async(id:string)=>{evaluationOpen.value=false;await router.push('/evaluations/'+id)};const date=(value:string)=>new Date(value).toLocaleString()</script>
<style scoped>.page{display:grid;gap:18px}header,.actions,.toolbar,.meta,.pager{display:flex;gap:10px;align-items:center}header{justify-content:space-between}h2{margin:0}.actions{flex-wrap:wrap;justify-content:flex-end}.toolbar input:first-child{flex:1}input,select,button{padding:9px;border:1px solid #cbd5e1;border-radius:7px;background:var(--n-color,#fff);color:inherit}.status{padding:4px 8px;background:#e0e7ff;border-radius:10px}.meta{color:#64748b}.notice{padding:12px;background:#fff7ed;color:#9a3412;border-radius:8px}.danger,.error{color:#b91c1c}.empty{text-align:center;padding:50px}.pager{justify-content:center}</style>


